using namespace std;

bool canHop(const string &amp;s, const string &amp;t) {
    // Check deletion move: t should be s with one letter removed.
    if(t.size() + 1 == s.size()){
        for (int i = 0; i &lt; s.size(); i++){
            string temp = s.substr(0, i) + s.substr(i+1);
            if(temp == t)
                return true;
        }
    }
    // Check replacement move: same length with exactly one differing letter.
    if(t.size() == s.size()){
        int diffCount = 0, diffIndex = -1;
        for (int i = 0; i &lt; s.size(); i++){
            if(s[i] != t[i]){
                diffCount++;
                diffIndex = i;
            }
        }
        if(diffCount == 1){
            // Replacement allowed if t[diffIndex] is alphabetically greater
            // than s[diffIndex] and exists later in s.
            if(t[diffIndex] &lt;= s[diffIndex])
                return false;
            for (int j = diffIndex + 1; j &lt; s.size(); j++){
                if(s[j] == t[diffIndex])
                    return true;
            }
        }
    }
    return false;
}

int main(){
    int N;
    cin &gt;&gt; N;
    vector&lt;string&gt; words(N);
    for (int i = 0; i &lt; N; i++){
        cin &gt;&gt; words[i];
    }
    vector&lt;vector&lt;int&gt;&gt; graph(N);
    // Build graph: directed edge from i to j if hop is possible from words[i] to words[j]
    for (int i = 0; i &lt; N; i++){
        for (int j = 0; j &lt; N; j++){
            if(i != j &amp;&amp; canHop(words[i], words[j])){
                graph[i].push_back(j);
            }
        }
