        if(dp[u] != -1)
            return dp[u];
        int best = 1;
        for (int v : graph[u]){
            best = max(best, 1 + dfs(v));
        }
        dp[u] = best;
        return best;
    };

    int ans = 0;
    for (int i = 0; i &lt; N; i++){
        ans = max(ans, dfs(i));
    }

    cout &lt;&lt; ans &lt;&lt; endl;
    return 0;
}
