using namespace std;

bool canHop(const string &amp;s, const string &amp;t) {
    if(t.size() + 1 == s.size()){
        for (int i = 0; i &lt; s.size(); i++){
            string temp = s.substr(0, i) + s.substr(i+1);
            if(temp == t)
