int main(){
    int N;
    cin &gt;&gt; N;
    vector&lt;string&gt; words(N);
    for(int i = 0; i &lt; N; i++){
        cin &gt;&gt; words[i];
    }
    vector&lt;vector&lt;int&gt;&gt; graph(N);
    vector&lt;int&gt; indegree(N, 0);
    for(int i = 0; i &lt; N; i++){
        for(int j = 0; j &lt; N; j++){
            if(i != j &amp;&amp; canHop(words[i], words[j])){
                graph[i].push_back(j);
                indegree[j]++;
            }
        }
    }

    // Topological sort using Kahn's algorithm
    vector&lt;int&gt; topo;
    queue&lt;int&gt; q;
    for(int i = 0; i &lt; N; i++){
        if(indegree[i] == 0)
            q.push(i);
    }
    while(!q.empty()){
        int u = q.front();
        q.pop();
        topo.push_back(u);
        for (int v : graph[u]){
            indegree[v]--;
            if(indegree[v] == 0)
                q.push(v);
        }
    }

    // Compute longest path using DP on the topologically sorted order
    vector&lt;int&gt; dp(N, 1);
    for(int i = topo.size()-1; i &gt;= 0; i--){
        int u = topo[i];
        for (int v : graph[u]){
            dp[u] = max(dp[u], 1 + dp[v]);
        }
    }

    int ans = 0;
    for (int i = 0; i &lt; N; i++){
        ans = max(ans, dp[i]);
    }
    cout &lt;&lt; ans &lt;&lt; endl;
    return 0;
}
