def main():
    import sys
    input_data = sys.stdin.read().split()
    N = int(input_data[0])
    words = input_data[1:]

    graph = [[] for _ in range(N)]
    indegree = [0] * N
    for i in range(N):
        for j in range(N):
            if i != j and can_hop(words[i], words[j]):
                graph[i].append(j)
                indegree[j] += 1

    # Topological sort using Kahn's algorithm
    topo = []
    q = deque([i for i in range(N) if indegree[i] == 0])
    while q:
        u = q.popleft()
        topo.append(u)
        for v in graph[u]:
            indegree[v] -= 1
            if indegree[v] == 0:
                q.append(v)

    dp = [1] * N
    for u in reversed(topo):
        for v in graph[u]:
            dp[u] = max(dp[u], 1 + dp[v])

    print(max(dp))

